mapper.select:
select sum(amount) as turnover from orders


        and order_time >= #{beginTime}


        and order_time <= #{endTime}


        and status = #{completed}

select count(id) from orders


        and order_time >= #{beginTime}


        and order_time <= #{endTime}


        and status = #{completed}

select  od.name,sum(od.number) from orders left join order_detail od on orders.id = od.order_id


        and order_time >= #{beginTime}


        and order_time <= #{endTime}


        and status = #{completed}


group by od.name
order by sum(od.number) desc
limit 10
